	if err != nil {
		return nil, "", fmt.Errorf("read %s: %w", path, err)
	}
	switch strings.ToLower(filepath.Ext(path)) {
	case ".yaml", ".yml":
		return data, "yaml", nil
	case ".json":
		return data, "json", nil
	}
	return data, "", nil
